    def test_evasion_stress(self):
        print(f"📊 Benchmarking {len(self.test_samples)} samples...")
        scores = []
        start_time = time.time()
        
        for i, text in enumerate(self.test_samples):
            # Process with high intensity (1.0)
            result = humanize_text(text, intensity=1.0)
            final_text = result["humanized_text"]
            final_score = result["humanized_score"]
            
            # Record score
            scores.append(final_score)
            
            status = "✅" if final_score < 15.0 else "⚠️" if final_score < 20.0 else "❌"
            print(f"Sample {i+1:02d} | Score: {final_score:5.1f}% | {status}")

            # Safety check: ensure text wasn't emptied
            self.assertTrue(len(final_text) > (len(text) * 0.7), f"Sample {i+1} lost too much text!")

        avg_score = sum(scores) / len(scores)
        pass_rate = (sum(1 for s in scores if s < 20.0) / len(scores)) * 100
        total_time = time.time() - start_time
        
        print("\n" + "="*60)
        print(f"RESULTS FOR {len(self.test_samples)} SAMPLES")
        print("="*60)
        print(f"Average AI Score : {avg_score:.2f}%")
        print(f"Bypass Rate (<20%): {pass_rate:.1f}%")
        print(f"Total Time      : {total_time:.2f}s")
        print("="*60)

        self.assertLess(avg_score, 15.0, "Average score should be below 15%")
        self.assertGreaterEqual(pass_rate, 90.0, "Pass rate should be at least 90%")

